  "filename": "core/hybrid/orchestration/great_function/standard/src/main/aletheion/vm/orchestrator/GreatFunctionStandard.kt",
  "language": "kotlin",
  "content": "package altheion.vm.orchestrator\n\nimport java.time.Instant\n\ndata class GreatFunctionSecurityPolicy(\n    val blacklist: List<String>,\n    val sandbox: Boolean,\n    val cfiEnabled: Boolean,\n    val offlineOnly: Boolean,\n    val allowNetwork: Boolean,\n    val maxCpuMillis: Long,\n    val maxMemoryBytes: Long,\n    val maxSteps: Int\n)\n\ndata class GreatFunctionParameter(\n    val name: String,\n    val type: String,\n    val required: Boolean,\n    val defaultValue: String?\n)\n\ndata class GreatFunctionStep(\n    val stepId: String,\n    val language: String,\n    val component: String,\n    val scriptPath: String,\n    val entryPoint: String,\n    val parameters: Map<String, String>,\n    val expects: List<String>,\n    val produces: List<String>,\n    val timeoutMillis: Long,\n    val retries: Int,\n    val haltOnFailure: Boolean\n)\n\ndata class GreatFunctionOutputSpecification(\n    val format: String,\n    val schemaUri: String,\n    val contentType: String,\n    val envelopeType: String\n)\n\ndata class GreatFunctionMetadata(\n    val functionName: String,\n    val version: String,\n    val description: String,\n    val author: String,\n    val timestamp: String,\n    val tags: List<String>\n)\n\ndata class GreatFunctionDefinition(\n    val metadata: GreatFunctionMetadata,\n    val securityPolicy: GreatFunctionSecurityPolicy,\n    val parameters: List<GreatFunctionParameter>,\n    val workflow: List<GreatFunctionStep>,\n    val outputSpecification: GreatFunctionOutputSpecification\n)\n\nsealed class GreatFunctionViolation {\n    data class BlacklistHit(val item: String, val stepId: String) : GreatFunctionViolation()\n    data class EmptyWorkflow(val functionName: String) : GreatFunctionViolation()\n    data class InvalidLanguage(val language: String, val stepId: String) : GreatFunctionViolation()\n    data class StepLimitExceeded(val functionName: String, val limit: Int) : GreatFunctionViolation()\n    data class ResourceLimitInvalid(val field: String, val value: Long) : GreatFunctionViolation()\n}\n\nobject GreatFunctionConstants {\n    val allowedLanguages = setOf(\"Kotlin/Android\", \"Lua\")\n    val mandatoryBlacklist = setOf(\n        \"SHA3-512\",\n        \"SHA3_512\",\n        \"SHA3 512\"\n    )\n}\n\nclass GreatFunctionValidator {\n    fun validate(definition: GreatFunctionDefinition): List<GreatFunctionViolation> {\n        val violations = mutableListOf<GreatFunctionViolation>()\n        if (definition.workflow.isEmpty()) {\n            violations += GreatFunctionViolation.EmptyWorkflow(definition.metadata.functionName)\n        }\n        if (definition.securityPolicy.maxSteps <= 0) {\n            violations += GreatFunctionViolation.ResourceLimitInvalid(\"maxSteps\", definition.securityPolicy.maxSteps.toLong())\n        }\n        if (definition.securityPolicy.maxCpuMillis <= 0) {\n            violations += GreatFunctionViolation.ResourceLimitInvalid(\"maxCpuMillis\", definition.securityPolicy.maxCpuMillis)\n        }\n        if (definition.securityPolicy.maxMemoryBytes <= 0) {\n            violations += GreatFunctionViolation.ResourceLimitInvalid(\"maxMemoryBytes\", definition.securityPolicy.maxMemoryBytes)\n        }\n        definition.securityPolicy.blacklist.forEach { item ->\n            if (item.trim().isNotEmpty()) {\n                definition.workflow.forEach { step ->\n                    if (containsProhibitedToken(item, step)) {\n                        violations += GreatFunctionViolation.BlacklistHit(item, step.stepId)\n                    }\n                }\n            }\n        }\n        GreatFunctionConstants.mandatoryBlacklist.forEach { required ->\n            if (!definition.securityPolicy.blacklist.contains(required)) {\n                violations += GreatFunctionViolation.BlacklistHit(required, \"global\")\n            }\n        }\n        definition.workflow.forEach { step ->\n            if (!GreatFunctionConstants.allowedLanguages.contains(step.language)) {\n                violations += GreatFunctionViolation.InvalidLanguage(step.language, step.stepId)\n            }\n        }\n        if (definition.workflow.size > definition.securityPolicy.maxSteps) {\n            violations += GreatFunctionViolation.StepLimitExceeded(\n                definition.metadata.functionName,\n                definition.securityPolicy.maxSteps\n            )\n        }\n        return violations\n    }\n\n    private fun containsProhibitedToken(token: String, step: GreatFunctionStep): Boolean {\n        val lowered = token.lowercase()\n        if (step.scriptPath.lowercase().contains(lowered)) return true\n        if (step.component.lowercase().contains(lowered)) return true\n        if (step.entryPoint.lowercase().contains(lowered)) return true\n        if (step.parameters.keys.any { it.lowercase().contains(lowered) }) return true\n        if (step.parameters.values.any { it.lowercase().contains(lowered) }) return true\n        return false\n    }\n}\n\nsealed class GreatFunctionExecutionResult {\n    data class Success(val functionName: String, val version: String, val output: String, val format: String) : GreatFunctionExecutionResult()\n    data class Failure(val functionName: String, val version: String, val violations: List<GreatFunctionViolation>) : GreatFunctionExecutionResult()\n}\n\ninterface KotlinGreatFunctionExecutor {\n    fun executeStep(step: GreatFunctionStep, context: MutableMap<String, Any?>): Boolean\n}\n\ninterface LuaGreatFunctionExecutor {\n    fun executeStep(step: GreatFunctionStep, context: MutableMap<String, Any?>): Boolean\n}\n\nclass GreatFunctionOrchestrator(\n    private val validator: GreatFunctionValidator,\n    private val kotlinExecutor: KotlinGreatFunctionExecutor,\n    private val luaExecutor: LuaGreatFunctionExecutor\n) {\n    fun execute(definition: GreatFunctionDefinition, initialContext: Map<String, Any?> = emptyMap()): GreatFunctionExecutionResult {\n        val violations = validator.validate(definition)\n        if (violations.isNotEmpty()) {\n            return GreatFunctionExecutionResult.Failure(\n                definition.metadata.functionName,\n                definition.metadata.version,\n                violations\n            )\n        }\n        val context = initialContext.toMutableMap()\n        definition.parameters.forEach { param ->\n            if (param.required && !context.containsKey(param.name) && param.defaultValue == null) {\n                return GreatFunctionExecutionResult.Failure(\n                    definition.metadata.functionName,\n                    definition.metadata.version,\n                    listOf(GreatFunctionViolation.ResourceLimitInvalid(\"missingParameter:${param.name}\", 0))\n                )\n            }\n            if (!context.containsKey(param.name) && param.defaultValue != null) {\n                context[param.name] = param.defaultValue\n            }\n        }\n        var stepsExecuted = 0\n        val start = Instant.now()\n        for (step in definition.workflow) {\n            if (stepsExecuted >= definition.securityPolicy.maxSteps) {\n                return GreatFunctionExecutionResult.Failure(\n                    definition.metadata.functionName,\n                    definition.metadata.version,\n                    listOf(GreatFunctionViolation.StepLimitExceeded(definition.metadata.functionName, definition.securityPolicy.maxSteps))\n                )\n            }\n            val ok = when (step.language) {\n                \"Kotlin/Android\" -> kotlinExecutor.executeStep(step, context)\n                \"Lua\" -> luaExecutor.executeStep(step, context)\n                else -> false\n            }\n            stepsExecuted += 1\n            if (!ok && step.haltOnFailure) {\n                return GreatFunctionExecutionResult.Failure(\n                    definition.metadata.functionName,\n                    definition.metadata.version,\n                    listOf(GreatFunctionViolation.InvalidLanguage(step.language, step.stepId))\n                )\n            }\n        }\n        val envelope = buildOutputEnvelope(definition, context, start, stepsExecuted)\n        return GreatFunctionExecutionResult.Success(\n            definition.metadata.functionName,\n            definition.metadata.version,\n            envelope,\n            definition.outputSpecification.format\n        )\n    }\n\n    private fun buildOutputEnvelope(\n        definition: GreatFunctionDefinition,\n        context: Map<String, Any?>,\n        start: Instant,\n        stepsExecuted: Int\n    ): String {\n        val now = Instant.now().toString()\n        val meta = definition.metadata\n        return \"{\" +\n            \"\\\"function_name\\\":\\\"\" + meta.functionName + \"\\\",\" +\n            \"\\\"version\\\":\\\"\" + meta.version + \"\\\",\" +\n            \"\\\"executed_at\\\":\\\"\" + now + \"\\\",\" +\n            \"\\\"steps_executed\\\":\" + stepsExecuted + \",\" +\n            \"\\\"output_format\\\":\\\"\" + definition.outputSpecification.format + \"\\\",\" +\n            \"\\\"schema_uri\\\":\\\"\" + definition.outputSpecification.schemaUri + \"\\\",\" +\n            \"\\\"context_snapshot\\\":\\\"\" + context.keys.joinToString(\"|\") + \"\\\"\" +\n            \"}\"\n    }\n}\n"
}
